def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 70.0 + np.sqrt(cap) * 30 + np.log1p(cap) * 18
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3) - np.sin(cap) * 45
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 50 * np.sin(cap * 2.1) - 25 * np.cos(usage * 5)
            else:
                base_priority -= 55 * usage + 30 * np.tanh(cap)
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.7) * 25 / (i**1.2)
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2100 * delta ** 1.9 + 250 * (1 - delta ** 0.6)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 28 / (j + 0.5)
            if int(cap * 4) % 5 == 1:
                base_priority += 55 * np.tan(cap / 10)
        elif 3 < usage <= 4:
            base_priority += 1600 * (usage - 3)**2.2 + 45 * np.sin(cap*4)
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 2:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 3)
                    if k == 11 and usage > 3.7:
                        fluctuation += 28
            if cap % 3.1 < 0.8:
                base_priority += 45 * np.cos(cap * 2.5)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2)**2 + 35 * np.cos(cap * 3)
            for m in range(1, 18):
                pow_val = usage ** m
                if pow_val < 0.55:
                    fluctuation += pow_val * 18 / m
                    if m % 6 == 3:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pow_val) * 15 / (m + 1)
                    if m == 14 and usage > 2.5:
                        fluctuation += 23
            if cap % 2.7 < 0.6:
                base_priority += 32 * np.sin(cap * 4)
        elif 1 < usage <= 2:
            base_priority += 950 * (usage - 1) ** 3 + 20 * np.sin(cap * 1.5)
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 28 / n
                    if n % 4 == 0:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 17 / (n + 2)
                    if n == 16 and usage > 1.5:
                        fluctuation += 18
            if cap % 1.7 < 0.4:
                base_priority += 30 * np.cos(cap * 3)
        elif 0.6 < usage <= 1:
            base_priority += 140 * (1 - usage) + 15 * np.cos(usage * 10)
            for o in range(1, 15):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.35) * 15 / o
                if usage < 0.08 * o:
                    fluctuation -= 9 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 6) * 28
        elif 0.1 < usage <= 0.6:
            base_priority += 300 * (1 - usage) ** 1.8 + 18 * np.sin(cap)
            for p in range(1, 20):
                pwr = usage ** p
                fluctuation += (np.cos(pwr * np.pi / 4) - 0.2) * 17 / p
                if usage < 0.025 * p:
                    fluctuation -= 11 * p
            if cap < 0.03:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        else:
            base_priority += 320 * (1 - usage) ** 2.5 + 22 * np.sin(usage * 8)
            for q in range(1, 22):
                pwr = usage ** q
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 15 / q
                if usage < 0.01 * q:
                    fluctuation -= 14 * q
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 400
            elif cap < 1.5:
                base_priority += np.log1p(cap * 35) * 55
            else:
                base_priority += (cap % 8) * 40
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 85
            if usage > 0.7:
                priority += 95
            elif usage < 0.1:
                priority -= 55
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25) + 5 * np.tanh(cap * r)
        elif cap < 1.0:
            priority += 50
            if usage > 0.8:
                priority += 70
            elif usage < 0.18:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1400) % (s + 5) in [0, 4]:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.9:
                priority += 110
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 21 == 0:
            proximity += 18
        if int(cap * 1050) % 25 == 0:
            proximity -= 13
        if int(cap * 210) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                proximity += 24 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk in [3,7]:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 3:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1 < 0.08:
                priority += 45
            if (int(cap * 3000) % 27 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 7):
                if (int(cap * 720) % (bb + 11) == 3) and (usage < 0.82):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
